import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.model.CardsOrNotes
import com.ichi2.anki.model.SortType
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.Robolectric
import com.ichi2.libanki.Consts

@RunWith(AndroidJUnit4::class)
class CardBrowserNoteSortTest : RobolectricTest() {

    @Test
    fun verifyNoteSortOrderRespected() {
        ensureCollectionLoadIsSynchronous()
        // Add two notes with different fields and creation times
        // Note 1: "B", Created first
        val n1 = addNoteUsingBasicModel("B", "back")
        n1.flush()

        // Note 2: "A", Created second
        val n2 = addNoteUsingBasicModel("A", "back")
        n2.flush()

        // Start Browser
        val controller = Robolectric.buildActivity(CardBrowser::class.java, Intent())
            .create().start().resume().visible()
        val browser = controller.get()
        saveControllerForCleanup(controller)

        // Switch to Notes mode
        browser.switchCardOrNote(CardsOrNotes.NOTES)
        RobolectricTest.advanceRobolectricUiLooper()

        // Verify default order (likely Created Time / ID, so B then A)
        // Actually ID order matches creation order usually.
        // N1 (B) id < N2 (A) id.

        // Sort by Field (noteFld). Should be A then B.
        browser.changeCardOrder(SortType.SORT_FIELD)
        RobolectricTest.advanceRobolectricUiLooper()

        // Check first item
        var firstItem = browser.cardsAdapter.getItem(0) as CardBrowser.CardCache
        var secondItem = browser.cardsAdapter.getItem(1) as CardBrowser.CardCache

        // n2 ("A") should be first
        assertThat("Sort by Field should show A first", firstItem.id, equalTo(n2.cids()[0]))
        assertThat("Sort by Field should show B second", secondItem.id, equalTo(n1.cids()[0]))

        // Change back to Created (noteCrt). Should be B then A.
        browser.changeCardOrder(SortType.CREATED_TIME)
        RobolectricTest.advanceRobolectricUiLooper()

        firstItem = browser.cardsAdapter.getItem(0) as CardBrowser.CardCache
        secondItem = browser.cardsAdapter.getItem(1) as CardBrowser.CardCache

        // n1 ("B") should be first
        assertThat("Sort by Created should show B first", firstItem.id, equalTo(n1.cids()[0]))
        assertThat("Sort by Created should show A second", secondItem.id, equalTo(n2.cids()[0]))
    }
}
